#include <bits/stdc++.h>
using namespace std;

const int N=8e5+10;

int n,a[N],v[N],l[N],r[N];
long long ans,f[N],t[N<<2];

void modify(int cur,int l,int r,int x,long long k){
    if(l==r){
        t[cur]=k;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,k);
    else
        modify(cur*2+1,mid+1,r,x,k);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}

long long query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    long long res=0;
    int mid=l+r>>1;
    if(x<=mid)
        res=max(res,query(cur*2,l,mid,x,y));
    if(y>mid)
        res=max(res,query(cur*2+1,mid+1,r,x,y));
    return res;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=2*n;i++){
        scanf("%d",&a[i]);
        if(l[a[i]]) r[a[i]]=i;
        else l[a[i]]=i;
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&v[i]);
    long long num=0;
    for(int i=1;i<=2*n;i++){
        if(l[a[i]]==i){
            f[a[i]]=max(num,query(1,1,2*n,l[a[i]]+1,r[a[i]]))+v[a[i]];
            ans=max(ans,f[a[i]]);
            modify(1,1,2*n,r[a[i]],num+v[a[i]]);
        }
        if(r[a[i]]==i)
            num=max(num,f[a[i]]);
    }
    printf("%lld",ans);
    return 0;
}
